INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6baa87d6-ab54-4df7-a2e8-9591d45797c7',
  '00000000-0000-0000-0000-000000000001',
  $escape$Swift - Setting up APNs for Push Notifications$escape$,
  $escape$To enable push notifications in an iOS app, you need to configure the APNs service in your Xcode project. First, create a new provisioning profile that includes push notifications, then add the APNs certificate to your project. In your app delegate, import the `UserNotifications` framework and handle the `UNUserNotificationCenterDelegate` protocol. To send a push notification, use `UNMutableNotificationContent` to create a notification content object, then schedule it with `UNUserNotificationCenter`.$escape$,
  $escape$import UserNotifications

class AppDelegate: UIResponder, UIApplicationDelegate, UNUserNotificationCenterDelegate {
    func application(_ application: UIApplication, didReceiveRemoteNotification userInfo: [AnyHashable: Any]) {
        print(userInfo)
    }

    func userNotificationCenter(_ center: UNUserNotificationCenter, didReceive response: UNNotificationResponse, withCompletionHandler completionHandler: @escaping () -> Void) {
        print(response.notification.request.content.userInfo)
    }
}$escape$,
  $escape$swift$escape$,
